let items = $input.all();

let results = [];

// ---- Config ----
const EXCLUDE_PREFIXES = [/^Detalhe_/i, /^News_/i];      // starts-with filters
const EXCLUDE_CONTAINS = []; // e.g. [/details_/i, /news_/i] if you want "contains" too

// Optional: require invoice-ish keywords in filename (set to true to enable)
const REQUIRE_INVOICE_KEYWORDS = false;
const INVOICE_KEYWORDS = /(invoice|inv\b|fatura|factura|recibo|nota\s*fiscal|tax\s*invoice|vat|iva)/i;

for (const item of items) {

  // ---- 1) Resolve email date (fallback = now) ----
  const rawDate =
    item.json.internalDate ||
    item.json.date ||
    item.json.headers?.date ||
    null;

  let date;
  if (rawDate && !isNaN(rawDate)) {
    date = new Date(Number(rawDate));
  } else if (rawDate) {
    date = new Date(rawDate);
  } else {
    date = new Date();
  }

  if (isNaN(date.getTime())) {
    date = new Date();
  }

  // ---- 2) Build MM-YYYY ----
  const month = String(date.getMonth() + 1).padStart(2, '0');
  const year = date.getFullYear();
  const monthYear = `${month}-${year}`;

  // ---- 3) Explode attachments ----
  for (const key of Object.keys(item.binary ?? {})) {
    const bin = item.binary[key];

    const fileName = (bin.fileName || '').trim();
    const fileNameLc = fileName.toLowerCase();

    const isPdf =
      (bin.mimeType && bin.mimeType.toLowerCase().includes('pdf')) ||
      fileNameLc.endsWith('.pdf');

    if (!isPdf) continue;

    // ---- 4) Exclude non-invoice PDFs by filename patterns ----
    const excludedByPrefix = EXCLUDE_PREFIXES.some((re) => re.test(fileName));
    const excludedByContains = EXCLUDE_CONTAINS.some((re) => re.test(fileName));

    if (excludedByPrefix || excludedByContains) continue;

    // ---- 5) Optional: only keep files that look like invoices by name ----
    if (REQUIRE_INVOICE_KEYWORDS && !INVOICE_KEYWORDS.test(fileName)) {
      continue;
    }

    results.push({
      json: {
        monthYear,             // <-- folder name
        fileName: bin.fileName,
        folderId: $input.first().json.id
      },
      binary: {
        data: bin              // normalize for Drive Upload
      }
    });
  }
}

return results;

